	public function getOrderTotals($order_id) {
		$query = $this->db->query("SELECT * FROM `" . DB_PREFIX . "order_total` WHERE order_id = '" . (int)$order_id . "' ORDER BY sort_order ASC");
		
		return $query->rows;
	}	
			
	public function addOrderHistory($order_id, $order_status_id, $comment = '', $notify = false, $override = false) {
		$order_info = $this->getOrder($order_id);
		// echo "<pre>";print_r($order_info);exit();
		if ($notify) {
		    $subject = '';
		    $message = '';

		    $order_date = date('d M Y', strtotime($order_info['date_added']));
		    $shipping_address = $order_info['shipping_address_1'] . ", " . $order_info['shipping_city'] . ", " . $order_info['shipping_zone'] . ", " . $order_info['shipping_country'] . " - " . $order_info['shipping_postcode'];

		    $order_products = $this->getOrderProducts($order_id);
		    $product_details = '';
		    foreach ($order_products as $product) {
		        $price = $this->currency->format($product['total'], $order_info['currency_code'], $order_info['currency_value']);
		        $product_details .= $product['name'] . ' x ' . $product['quantity'] . ' - ' . $price . "\n";
		    }

