        $message .= "Payment Method: " . $payment_method . "\n\n";
        $message .= "Your order will be shipped to the address provided, and you will receive a tracking number once it has been dispatched.\n";
        $message .= "Estimated Delivery Date: " . $delivery_date . "\n\n";
        $message .= "If you have any questions or need assistance with your order, please contact our support team at contact@onlinesolutionsrx.com or call us at +1-7076-667-713.\n\n";
        $message .= "Thank you for shopping with OnlineSolutionsRx!\n\n";
        $message .= "Best regards,\n";
        $message .= "The OnlineSolutionsRx Team\n";
        $message .= "https://www.onlinesolutionsrx.com\n";

        $mail->setText($message);
        $mail->send();

		//  Now send email to admin
		$admin_email = $this->config->get('config_email'); // Admin email from config
		$admin_name = "Admin"; // Change if you want dynamic admin name

		$adminMail = new Mail();
		$adminMail->parameter = $this->config->get('config_mail_parameter');
		$adminMail->smtp_hostname = $this->config->get('config_mail_smtp_hostname');
		$adminMail->smtp_username = $this->config->get('config_mail_smtp_username');
		$adminMail->smtp_password = html_entity_decode($this->config->get('config_mail_smtp_password'), ENT_QUOTES, 'UTF-8');
		$adminMail->smtp_port = $this->config->get('config_mail_smtp_port');
		$adminMail->smtp_timeout = $this->config->get('config_mail_smtp_timeout');

		$adminMail->setTo($admin_email);
		$adminMail->setFrom($this->config->get('config_email'));
		$adminMail->setSender($order_info['store_name']);
		$adminMail->setSubject('New Order Received - #' . $order_info['order_id'] . ' from OnlineSolutionsRx');

		// Reuse same values from earlier
		$order_date = date('d M Y', strtotime($order_info['date_added']));
		$shipping_address = $order_info['shipping_address_1'] . ", " . $order_info['shipping_city'] . ", " . $order_info['shipping_zone'] . ", " . $order_info['shipping_country'] . " - " . $order_info['shipping_postcode'];

		$product_details_admin = '';
		foreach ($order_products as $product) {
		$price = $this->currency->format($product['total'], $order_info['currency_code'], $order_info['currency_value']);
		$product_details_admin .= $product['name'] . ' x ' . $product['quantity'] . ' - ' . $price . "\n";
		}

		$admin_message = "Dear " . $admin_name . ",\n\n";
		$admin_message .= "A new order has been placed on the OnlineSolutionsRx website. Below are the details of the order:\n\n";
		$admin_message .= "Order ID: #" . $order_info['order_id'] . "\n";
		$admin_message .= "Order Date: " . $order_date . "\n";
		$admin_message .= "Customer Name: " . $order_info['firstname'] . " " . $order_info['lastname'] . "\n";
		$admin_message .= "Customer Email: " . $order_info['email'] . "\n\n";
		$admin_message .= "Shipping Address:\n" . $shipping_address . "\n\n";
		$admin_message .= "Product(s) Ordered:\n" . $product_details_admin . "\n";
		$admin_message .= "Total Amount: " . $total_amount . "\n";
